var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"제가 발을 묶겠습니다! 도망치세요 실비아 씨!","JPN":"僕が足止めしますから！　逃げて、シルビアさん！","ENG":"I'll keep it busy. Run, Sylvia!","TWN":"我來拖住它！請逃走吧，希爾維亞小姐！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카일!","JPN":"カイル！","ENG":"Kyle!","TWN":"凱爾！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"크으윽!!","JPN":"くううっ！！","ENG":"Ugh!","TWN":"唔呃呃！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"카일! 정신차려! 괜찮아?","JPN":"カイル！　しっかりして！　大丈夫？","ENG":"Kyle! Wake up! You alright?","TWN":"凱爾！振作點！你沒事吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"괘, 괜찮습니다...... 이 정도는......","JPN":"だ、大丈夫です……これくらいは……","ENG":"I-I'm okay... I can handle this...","TWN":"沒、沒事……這種小傷……"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"바보 같은 소리 마! 온 몸이 피투성이잖아?","JPN":"バカ言わないでよ！　全身血だらけじゃない！","ENG":"No, you can't! Look at you—you're bleeding all over!","TWN":"別說傻話了！你全身都是血啊？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"방금 녀석의 침식파 시그니처를 확인했어.","JPN":"さっきの奴の侵食波シグネチャーを確認したわ。","ENG":"I've checked its Corruption Ray signature.","TWN":"我剛才確認了這傢伙的侵蝕波標誌。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"예상대로 저건 4종 침식체라고! 이런 소규모 병력으로 어쩔 상대가 아니야!","JPN":"案の定、あれは第4種侵食体よ！　こんな少人数の兵力じゃどうしようもない！　","ENG":"We were right. It's Category 4. We're not equipped to fight that thing.","TWN":"和預料得一樣，那是4類侵蝕體！以我們這種小規模兵力，是沒辦法對付它的！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"젠장, 어디서 저런 괴물이 튀어나온 거야?","JPN":"くそっ、どこからあんなバケモノが現れたわけ？","ENG":"Goddamnit, where did it come from?!","TWN":"可惡，那種怪物是從哪裡冒出來的啊？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만...... 놈을 막지 못하면 등대가......","JPN":"でも……奴を食い止めなければ、灯台が……","ENG":"But... if we don't stop it, the Lighthouse...","TWN":"可是……我們不擋下它的話，燈塔會……"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"으, 으아악!!","JPN":"う、うわああ！！","ENG":"W-waaah!","TWN":"啊，啊啊啊！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SLASH_BIG"},{"id":"L29_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"도, 도망쳐! 이젠 끝났어!!","JPN":"に、逃げろ！　もうおしまいだ！！","ENG":"R-run! It's over!","TWN":"快、快逃！已經完蛋了！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"멍청한 소리 할 시간 있으면 이거나 빨리 트럭에 실어!","JPN":"バカ言ってる暇があるなら、これでもさっさとトラックに載せろ！","ENG":"Stop yammering and load this on the truck!","TWN":"有空說傻話，還不快點把它裝上卡車！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"뭐하는 겁니까, 당장 도망가도 모자랄 판에?!","JPN":"何を言ってるんです、今は逃げる以外の選択肢はないんじゃ！？","ENG":"What are you doing? We have to run while we can!","TWN":"你是要幹嘛，我們現在連逃跑都來不及了啊？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"도망칠 때 치더라도 등대는 수거해야지!","JPN":"逃げるにしても、灯台は回収しないと！","ENG":"We'll run, but not without the Lighthouse!","TWN":"就算要逃跑，也要回收燈塔啊！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"전부 다 실을 필요는 없어. 고출력 지향성 신호를 발생시키는 핵심부만 무사하면 돼.","JPN":"すべて載せる必要はない。\\n高出力の指向性信号を発生させるコアさえ無事ならいいんだ。","ENG":"We don't have to take all of it. We just need its core part that generates high-powered directional signals.","TWN":"不需要把全部都裝上來，只要發射高功率定向信號的核心沒事就行，"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그럼 나중에라도 등대를 재설치해서 차원 폭풍 안의 아군을 구할 수 있다고!","JPN":"そうすれば、いずれ灯台を再設置して、次元の暴風の中にいる味方を助け出すことができる！","ENG":"Then we'll be able to reinstall the Lighthouse and save our people in the dimensional storm!","TWN":"這樣之後還能重新設置燈塔，救出次元風暴內的友軍！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"그, 그래도 이런 상황에서 한가하게 장비나 챙길 여유가 어디 있습니까?!","JPN":"そ、そうだとしても今はのんびり装備を回収してる余裕なんてありませんよ！？","ENG":"B-but still, we don't have the time to pack the equipment. Let's go!","TWN":"可、可是，這種情況下，哪裡還有閒工夫去收拾裝備啊？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"아까 제이크 소령 말 못 들었나?","JPN":"さっきのジェイク少佐の言葉が聞こえなかったのか？","ENG":"Didn't you hear Major Walker earlier?","TWN":"你沒聽到傑克上校剛才說的話嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L39_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"전우를 버리는 쓰레기는 정보부에도 필요 없어!","JPN":"戦友を見捨てるようなクズ野郎は、情報局にもいらねえんだよ！","ENG":"No one in the Intelligence Agency abandons his people!","TWN":"情報部也不需要拋棄戰友的垃圾！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"목숨까지 버리라고는 안 해! 하지만 할 수 있는 데까지는 해 보는 거야!","JPN":"捨て身でやれとまでは言わない！　けど、やれるとこまではやってみるんだ！","ENG":"I'm not asking you to throw your life away for them; I'm asking you to try your best to save them.","TWN":"而且我也沒叫你捨棄自己的性命！但我們能做多少就要做多少！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"제, 젠장! 알겠습니다! 여기에 실으면 됩니까?","JPN":"ち、ちくしょう！　わかりました！　ここに載せればいいんですか？","ENG":"G-goddamnit! Okay! You want me to put it here?","TWN":"該、該死的！知道了！裝上去就行了是吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그래! 이제야 말이 통하는군!","JPN":"そうだ！　やっとわかってくれたか！","ENG":"Yes! Finally!","TWN":"沒錯！我們語言終於能互通了！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"서둘러요! 놈이 이쪽으로 다가옵니다!!","JPN":"急いで！　奴がこっちへ近づいてきます！！","ENG":"Hurry! The C.O. is coming our way!","TWN":"快點！那傢伙往這邊來了！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"젠장, 방어병력이 주의를 끌고 있는데도 무시하고 이쪽으로 먼저 다가오다니......","JPN":"くそ、防御兵が注意をひいているのも無視して、こちらにくるとは……","ENG":"Drat, the others are trying to distract it, and it's completely ignoring them.","TWN":"該死，明明防禦兵力正在吸引它的注意力，它竟然無視他們，直接往這裡來了……"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"설마 등대의 신호에 자극 받고 있는 건가?","JPN":"まさか灯台の信号に刺激されているのか？","ENG":"Is it being stimulated by the Lighthouse's signals?","TWN":"該不會是受到燈塔信號的刺激吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"뭐해요! 빨리 타요!","JPN":"何してるんです、早く乗ってください！","ENG":"What are you doing? Get in!","TWN":"你在做什麼！快上車啊！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"먼저 출발해! 난 확인해 볼 게 있으니까!","JPN":"先に出発しろ！　私は確認したいことがある！","ENG":"You go first. I want to check something.","TWN":"你先走！我還有事情要確認！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"네?! 무슨 헛소리입니까? 자살하려면 다른 방법도 많다고요!","JPN":"はい！？　冗談言わないでくださいよ。\\n自殺したいなら他にいくらでも方法はありますから！　","ENG":"What?! What are you talking about? There are more peaceful ways to commit suicide, you know!","TWN":"什麼？！你在胡說什麼？你要自殺的話，其他方法還多得是呢！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"걱정 마! 바퀴벌레 같은 생명력이야말로 훌륭한 정보부 요원의 자격이니까!","JPN":"心配いらない！　ゴキブリ並みの生命力こそが、情報局員の誇りだ！","ENG":"Don't worry. We intelligence agents are hard to kill. Just like cockroaches.","TWN":"別擔心！擁有像小強一樣的生命力，才有資格當優秀的情報部要員！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그러니까 빨리 가라고!","JPN":"だから、早く行け！","ENG":"So, go!","TWN":"所以你快走！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_EXTRA_NULL_NULL","text":{"KOREA":"젠장, 알겠습니다! 죽지 마세요!!","JPN":"くそ、了解です！　どうかご無事で！！","ENG":"Goddamnit, okay! You'd better not die!","TWN":"該死，知道了！你別死啊！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_18"},{"id":"L14_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"좋아. 등대의 신호 패턴이 분명 이런 식이었지......","JPN":"よし、確か灯台の信号パターンはこうだったよな……","ENG":"Alright, the Lighthouse's signal pattern was like this...","TWN":"很好，燈塔的信號模式應該是這樣吧……"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_13"},{"id":"L15_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"기지 레이더에 이 패턴을 입력하면...... 간이 디코이가 완성이로군.","JPN":"基地レーダーにこのパターンを入力すれば……簡易デコイが完成っと。","ENG":"If I enter this pattern to the base radar... Now, we've got a temporary decoy.","TWN":"只要在基地雷達裡輸入這個模式……簡易誘餌就完成了。"},"stage":{"bg":"WAREHOUSE_01","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_04"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"크워어?!","JPN":"グアア！？","ENG":"Rawr?!","TWN":"唔哦哦？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_20"},{"id":"L21_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"좋아! 잘 작동하는걸! 그럼 나도 슬슬 내빼볼까......","JPN":"よし！　うまくいってるな！　さて、私もそろそろ退散しようか……","ENG":"Alright, it works! Now, I'd better go...","TWN":"很好！功能正常發揮！那我也悄悄溜走吧……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"크으윽!!","JPN":"くううっ！！　","ENG":"Ugh!","TWN":"唔呃呃！！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"빌어먹을 침식체 놈이...... 원거리 공격을 한다는 말은 없었잖아......?","JPN":"くそ侵食体め……遠距離攻撃をするなんて聞いてないぞ……","ENG":"That stupid C.O.! No one said it was capable of ranged attacks!","TWN":"那群該死的侵蝕體……可沒人告訴過我它們還會遠距離攻擊啊？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"다리가 부러졌나......? 나도 여기까지인가 보군......","JPN":"足を骨折している……？　私もここまでか……","ENG":"Did I break my leg? Maybe this is it for me.","TWN":"腿斷了嗎？看來我到此為止了……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"뭐, 그래도 등대는 지켰으니까 수지는 맞는 장사로군.","JPN":"まあでも、灯台は守れたからギブアンドテイクってとこか。","ENG":"Well, at least I protected the Lighthouse. I didn't do too badly.","TWN":"不過，我保護了燈塔，這筆交易也不虧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......봤지, 군바리 친구들? 정보부 뺀질이들도 할 때는 한다고?","JPN":"……見てただろう、軍人の諸君？　情報局員もやる時はやるんだからな？","ENG":"You see, GIs? Even we spies rise to the occasion sometimes.","TWN":"……看見了嗎，士兵朋友們？情報部的滑頭們在該幹的時候，也是會幹的。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"그래, 인정하지. 확실히 할 때는 제대로 해주는걸.","JPN":"ああ、認めるさ。確かにやるべき時にはしっかりやってくれるんだな。","ENG":"Yes, you do. And you do it well.","TWN":"嗯，我承認。在該幹的時候確實幹得很好。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......뭐야, 나 살아 있나? 어떻게......?","JPN":"……なんだ、生きてるのか？　どうやって……？","ENG":"Huh? Am I still alive? But how?","TWN":"……什麼啊，我還活著嗎？怎麼會……？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"제이크 소령?! 당신이 막아준 건가?","JPN":"ジェイク少佐！？　君が助けてくれたのか？","ENG":"Major Walker? Did you stop it for me?","TWN":"傑克少校？！是你擋下它了嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래. 다친 곳은 없나?","JPN":"そうさ、ケガはないかい？","ENG":"I did. You're not hurt, are you?","TWN":"是啊，你沒有受傷吧？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"없기는! 젠장! 여기 멍든 거 안 보이나? 너무 늦었잖아!","JPN":"ないと思うか！　くそ！\\nここにあざができてるだろ？　ずいぶん遅かったじゃないか！","ENG":"Yes, I am! Goddamnit! Can't you see I'm bruised? You were late!","TWN":"什麼沒受傷！該死！你沒看見這裡在流血嗎？你來得太慢了！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"늦어서 미안하군. 차원 폭풍을 뚫고 나오느라 꽤 헤맸거든.","JPN":"遅れてすまないな。次元の暴風を突破するのに手こずったんだ。","ENG":"I'm sorry I couldn't come sooner. It was difficult to find my way out of that dimensional storm.","TWN":"來晚了，真是抱歉。我們為了突破次元風暴，在裡面迷路了好久。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"사과는 됐어. 그나저나......","JPN":"詫びはいい。それより……","ENG":"No need to apologize. Anyway...","TWN":"別道歉了，總之……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"......저건 어떡할 건가?","JPN":"……あれはどうするんだ？","ENG":"What are you going to do about that?","TWN":"……那東西該怎麼辦啊？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"저건 아무리 봐도 제 4종 침식체야.","JPN":"あれはどう見ても第4種侵食体。","ENG":"It's definitely Category 4.","TWN":"不管怎麼看，都是第4類侵蝕體吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"역시 모두 살아남는 건 무리겠지?","JPN":"さすがに全員無事のままは無理だろう？","ENG":"There's no way we can survive it, is there?","TWN":"我們果然沒辦法全員活下來嗎？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"저런 걸 우리 같은 준비도 안 된 소부대로 상대하는 건 불가능하니까......","JPN":"我々のように準備不足な小部隊が、あんなのを相手にすることはできまい……","ENG":"We're too few and not equipped at all to fight something like that.","TWN":"像我們這樣毫無準備的小部隊，要對上那玩意幾乎沒有勝算……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그러니까 난 내버려 두고 등대라도 지킬 수 있게 빨리 그쪽으로 합류하라고.","JPN":"だから、私のことは気にしなくて良い。\\n灯台だけでも守れるように、早く向こうに合流して……","ENG":"So... just leave me here and go join the others to protect the Lighthouse.","TWN":"所以別管我了，要守住燈塔，你得快去那邊和他們會合才行。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"이, 이봐. 소령! 뭐 하는 건가?","JPN":"お、おい、少佐！　何をしている？","ENG":"H-hey, Major! What are you doing?","TWN":"喂、喂。少校！你在做什麼？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"그쪽이 아니야! 등대는 반대편이라고!","JPN":"そっちじゃない！　灯台は反対側だ！","ENG":"You're going the wrong way! The Lighthouse is on the other side!","TWN":"不是那邊！燈塔在反方向！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭐, 군인이란 게 언제 죽을지 모르는 직업이긴 하지.","JPN":"まあ、軍人っていつ死ぬかわからない職業ではあるよな。","ENG":"Well, being a soldier means you can die anytime.","TWN":"確實，所謂的軍人，是個不知何時會死掉的職業。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 걱정 마, 적어도 오늘은 아무도 안 죽는 날이니까.","JPN":"けど、心配するな。少なくとも、今日は誰も死なない日だから。","ENG":"But don't worry. None of us is going to die. Not today at least.","TWN":"不過不用擔心，至少今天不會有任何人死掉。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"왜냐하면......","JPN":"なぜなら……","ENG":"Because...","TWN":"至於為什麼……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"내가 그렇게 결정했거든.","JPN":"俺がそう決めたんだ。","ENG":"that's what I've decided.","TWN":"因為這是我決定的。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MARK_NPC_NULL_NULL","text":{"KOREA":"소령......?","JPN":"少佐……？","ENG":"Major?","TWN":"少校？"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MARK_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"다들 물러서!","JPN":"全員下がれ！　","ENG":"Everyone, get back!","TWN":"全體後退！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"소, 소령님?!","JPN":"しょ、少佐！？","ENG":"M-Major?!","TWN":"少、少校大人？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"버터맨! 혼자 뭐 하려는 거야?!","JPN":"バターマン！　一人で何をするつもり！？","ENG":"Sleazeball! What are you trying to do?!","TWN":"小白臉！你一個人想幹什麼啊？！"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"제 4종 침식체라...... 그럼 마음껏 날뛰어봐도 되겠군.","JPN":"第4種侵食体か……じゃあ、思う存分暴れても大丈夫そうだな。","ENG":"Category 4, huh? Finally, I have a chance to knock myself out fighting.","TWN":"4類侵蝕體嗎……那我可以盡情大鬧一場了呢。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"델타 세븐이 어떤 부대인지, 우리가 어떤 적들을 상대하기 위해 만들어졌는지......","JPN":"デルタセブンがどんな部隊で、我々がどんな敵を相手にするために集められたのか……","ENG":"I'll show you who we Delta Sevens are,","TWN":"第七三角洲是怎樣的部隊……我們又是為了和什麼樣的敵人戰鬥而創建的……"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"지금부터 알려주마.","JPN":"今から知らしめてやろう。","ENG":"and what we're made of.","TWN":"現在，我就來告訴你答案吧。"},"stage":{"bg":"WAREHOUSE_01","bgm":"CUTSCENE_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};